'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { getSubjects, getEnrollments, addEnrollment, Subject } from '@/utils/storage';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Plus, CheckCircle } from 'lucide-react';
import { toast } from 'sonner';

interface EnrollSubjectDialogProps {
  onEnrolled: () => void;
}

export default function EnrollSubjectDialog({ onEnrolled }: EnrollSubjectDialogProps) {
  const { user } = useAuth();
  const [open, setOpen] = useState(false);
  const [availableSubjects, setAvailableSubjects] = useState<Subject[]>([]);

  useEffect(() => {
    if (open) {
      loadAvailableSubjects();
    }
  }, [open, user]);

  const loadAvailableSubjects = () => {
    const subjects = getSubjects();
    const enrollments = getEnrollments();
    
    const myEnrollments = enrollments.filter(e => e.studentId === user?.id);
    const enrolledSubjectIds = myEnrollments.map(e => e.subjectId);
    
    const available = subjects.filter(s => !enrolledSubjectIds.includes(s.id));
    setAvailableSubjects(available);
  };

  const handleEnroll = (subject: Subject) => {
    const enrollment = {
      id: `ENR-${Date.now()}`,
      studentId: user!.id,
      subjectId: subject.id,
      enrolledAt: new Date().toISOString(),
      status: 'pending' as const
    };

    addEnrollment(enrollment);
    toast.success(`Enrollment request sent for ${subject.name}! Waiting for teacher approval.`);
    setOpen(false);
    onEnrolled();
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button className="bg-[#E30613] hover:bg-[#E30613]/90">
          <Plus className="w-4 h-4 mr-2" />
          Enroll in Subject
        </Button>
      </DialogTrigger>
      <DialogContent className="sm:max-w-2xl max-h-[80vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Enroll in a Subject</DialogTitle>
          <DialogDescription>Select a subject to enroll in</DialogDescription>
        </DialogHeader>
        
        <div className="space-y-3 pt-4">
          {availableSubjects.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground border-2 border-dashed rounded-xl">
              No available subjects to enroll in at this time.
            </div>
          ) : (
            availableSubjects.map((subject) => (
              <div
                key={subject.id}
                className="p-4 border rounded-xl hover:bg-secondary transition-colors"
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <h4 className="font-bold text-lg">{subject.name}</h4>
                    <p className="text-sm text-muted-foreground mt-1">
                      Instructor: {subject.teacherName}
                    </p>
                    <p className="text-sm text-muted-foreground">
                      Schedule: {subject.day} • {subject.time}
                    </p>
                  </div>
                  <Button
                    onClick={() => handleEnroll(subject)}
                    size="sm"
                    className="bg-[#E30613] hover:bg-[#E30613]/90"
                  >
                    <CheckCircle className="w-4 h-4 mr-2" />
                    Enroll Now
                  </Button>
                </div>
              </div>
            ))
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}
