'use client';

import { useState } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { CheckCircle, LogIn, LogOut as LogOutIcon, QrCode, ShieldCheck } from 'lucide-react';
import { toast } from 'sonner';
import { getAttendancesAction, addAttendanceAction, updateAttendanceAction, getUsersAction, getSubjectsAction, getEnrollmentsAction } from '@/app/actions/dbActions';

type ScanMode = 'in' | 'out';

export default function QRScanner() {
  const [scanMode, setScanMode] = useState<ScanMode>('in');
  const [qrData, setQrData] = useState('');
  const [lastScanned, setLastScanned] = useState<{ studentName: string; subjectName: string; mode: ScanMode } | null>(null);
  const [loading, setLoading] = useState(false);

  const handleScanIn = async () => {
    if (!qrData) {
      toast.error('Enter student ID string');
      return;
    }
    setLoading(true);

    try {
      const [studentId, subjectId] = qrData.split('|');
      const users = await getUsersAction();
      const subjects = await getSubjectsAction();
      const enrollments = await getEnrollmentsAction();
      
      const student = users.find(u => u.id === studentId);
      const subject = subjects.find(s => s.id === subjectId);
      
      if (!student || !subject) {
        toast.error('Invalid ID or Subject pairing');
        setLoading(false);
        return;
      }

      const enrollment = enrollments.find(e => 
        e.studentId === studentId && 
        e.subjectId === subjectId && 
        e.status === 'approved'
      );

      if (!enrollment) {
        toast.error('Student not approved for this class');
        setLoading(false);
        return;
      }

      const todayDate = new Date().toISOString().split('T')[0];
      const existingAttendances = await getAttendancesAction();
      
      const alreadyScannedIn = existingAttendances.find(a => 
        a.studentId === studentId && 
        a.subjectId === subjectId && 
        a.date.startsWith(todayDate) &&
        a.timeIn
      );

      if (alreadyScannedIn) {
        toast.warning('Already recorded entrance for today');
        setLoading(false);
        return;
      }

      const attendance = {
        id: `ATT-${Date.now()}`,
        studentId,
        subjectId,
        date: new Date().toISOString(),
        status: 'present' as const,
        timeIn: new Date().toLocaleTimeString('en-US', { hour12: false }),
        sessionId: `SESS-${Date.now()}`
      };

      await addAttendanceAction(attendance);
      setLastScanned({ studentName: student.name, subjectName: subject.name, mode: 'in' });
      toast.success(`${student.name} confirmed for ${subject.name}`);
      setQrData('');
    } catch (error) {
      toast.error('Capture error');
    } finally {
      setLoading(false);
    }
  };

  const handleScanOut = async () => {
    if (!qrData) {
      toast.error('Enter student ID string');
      return;
    }
    setLoading(true);

    try {
      const [studentId, subjectId] = qrData.split('|');
      const users = await getUsersAction();
      const subjects = await getSubjectsAction();
      
      const student = users.find(u => u.id === studentId);
      const subject = subjects.find(s => s.id === subjectId);
      
      if (!student || !subject) {
        toast.error('Invalid credentials');
        setLoading(false);
        return;
      }

      const todayDate = new Date().toISOString().split('T')[0];
      const existingAttendances = await getAttendancesAction();
      
      const todayAttendance = existingAttendances.find(a => 
        a.studentId === studentId && 
        a.subjectId === subjectId && 
        a.date.startsWith(todayDate) &&
        a.timeIn &&
        !a.timeOut
      );

      if (!todayAttendance) {
        toast.error('No matching entrance record found');
        setLoading(false);
        return;
      }

      await updateAttendanceAction(todayAttendance.id, {
        timeOut: new Date().toLocaleTimeString('en-US', { hour12: false })
      });

      setLastScanned({ studentName: student.name, subjectName: subject.name, mode: 'out' });
      toast.success(`${student.name} dismissed from ${subject.name}`);
      setQrData('');
    } catch (error) {
      toast.error('Dismissal error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-10 pb-20">
      <div className="text-center py-10">
        <div className="inline-flex h-20 w-20 items-center justify-center bg-primary/10 rounded-[2rem] mb-6 shadow-xl shadow-primary/5">
          <QrCode className="h-10 w-10 text-primary" />
        </div>
        <h2 className="text-4xl font-black tracking-tighter">Attendance Capture</h2>
        <p className="text-muted-foreground font-bold italic mt-2">Professional session logging via digital ID</p>
      </div>

      <Tabs value={scanMode} onValueChange={(v) => setScanMode(v as ScanMode)}>
        <TabsList className="grid w-full grid-cols-2 bg-white border border-primary/10 h-16 p-1.5 rounded-[1.5rem] shadow-sm">
          <TabsTrigger value="in" className="rounded-xl font-black uppercase text-[10px] tracking-widest data-[state=active]:bg-[#E30613] data-[state=active]:text-white transition-all">
            <LogIn className="w-4 h-4 mr-2" />
            Class Entrance
          </TabsTrigger>
          <TabsTrigger value="out" className="rounded-xl font-black uppercase text-[10px] tracking-widest data-[state=active]:bg-[#E30613] data-[state=active]:text-white transition-all">
            <LogOutIcon className="w-4 h-4 mr-2" />
            Class Dismissal
          </TabsTrigger>
        </TabsList>

        <div className="mt-10">
          <TabsContent value="in">
            <Card className="border-primary/5 shadow-2xl rounded-[2.5rem] overflow-hidden">
              <div className="h-3 bg-[#E30613]" />
              <CardHeader className="text-center pb-0 pt-10">
                <CardTitle className="text-3xl font-black">Entrance Scan</CardTitle>
                <CardDescription className="font-bold">Verify student arrival</CardDescription>
              </CardHeader>
              <CardContent className="p-10 space-y-8">
                <div className="space-y-3">
                  <Label className="font-black text-[10px] uppercase tracking-widest text-muted-foreground">Manual Code Input</Label>
                  <Input
                    className="h-16 bg-muted/50 rounded-2xl text-center font-black text-xl tracking-widest border-primary/5 focus:border-primary transition-all"
                    placeholder="STUDENT_ID|SUBJECT_ID"
                    value={qrData}
                    onChange={(e) => setQrData(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleScanIn()}
                  />
                </div>
                <Button 
                  onClick={handleScanIn} 
                  disabled={loading}
                  className="w-full h-16 bg-[#E30613] hover:bg-[#E30613]/90 text-white font-black rounded-2xl shadow-2xl shadow-[#E30613]/20 text-xl tracking-widest"
                >
                  {loading ? 'SYNCING...' : 'CONFIRM ENTRY'}
                </Button>

                {lastScanned && lastScanned.mode === 'in' && (
                  <div className="p-8 bg-green-50 border-2 border-green-100 rounded-[2rem] animate-in slide-in-from-top-4 duration-500 shadow-lg">
                    <div className="flex items-center gap-5">
                      <div className="h-14 w-14 rounded-2xl bg-green-500 flex items-center justify-center shadow-lg shadow-green-500/20">
                        <CheckCircle className="w-8 h-8 text-white" />
                      </div>
                      <div>
                        <p className="font-black text-green-900 uppercase text-[10px] tracking-[0.2em] mb-1">Entrance Logged</p>
                        <p className="text-2xl font-black text-green-800">{lastScanned.studentName}</p>
                        <p className="text-xs text-green-600 font-black uppercase tracking-widest">{lastScanned.subjectName}</p>
                      </div>
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="out">
            <Card className="border-primary/5 shadow-2xl rounded-[2.5rem] overflow-hidden">
              <div className="h-3 bg-[#E30613]" />
              <CardHeader className="text-center pb-0 pt-10">
                <CardTitle className="text-3xl font-black">Dismissal Scan</CardTitle>
                <CardDescription className="font-bold">Finalize session activity</CardDescription>
              </CardHeader>
              <CardContent className="p-10 space-y-8">
                <div className="space-y-3">
                  <Label className="font-black text-[10px] uppercase tracking-widest text-muted-foreground">Manual Code Input</Label>
                  <Input
                    className="h-16 bg-muted/50 rounded-2xl text-center font-black text-xl tracking-widest border-primary/5 focus:border-primary transition-all"
                    placeholder="STUDENT_ID|SUBJECT_ID"
                    value={qrData}
                    onChange={(e) => setQrData(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleScanOut()}
                  />
                </div>
                <Button 
                  onClick={handleScanOut} 
                  disabled={loading}
                  className="w-full h-16 bg-[#E30613] hover:bg-[#E30613]/90 text-white font-black rounded-2xl shadow-2xl shadow-[#E30613]/20 text-xl tracking-widest"
                >
                  {loading ? 'SYNCING...' : 'CONFIRM DISMISSAL'}
                </Button>

                {lastScanned && lastScanned.mode === 'out' && (
                  <div className="p-8 bg-primary/5 border-2 border-primary/10 rounded-[2rem] animate-in slide-in-from-top-4 duration-500 shadow-lg">
                    <div className="flex items-center gap-5">
                      <div className="h-14 w-14 rounded-2xl bg-primary flex items-center justify-center shadow-lg shadow-primary/20">
                        <ShieldCheck className="w-8 h-8 text-white" />
                      </div>
                      <div>
                        <p className="font-black text-primary uppercase text-[10px] tracking-[0.2em] mb-1">Exit Logged</p>
                        <p className="text-2xl font-black text-primary/80">{lastScanned.studentName}</p>
                        <p className="text-xs text-primary/60 font-black uppercase tracking-widest">{lastScanned.subjectName}</p>
                      </div>
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>
        </div>
      </Tabs>
    </div>
  );
}